import { defineStore } from 'pinia'

export const useAuthStore = defineStore('auth', {
  // El estado: la información que queremos almacenar
  state: () => ({
    user: null, // Objeto con los datos del usuario
    token: null, // El token de autenticación
    isAuthenticated: false, // Un booleano que indica el estado
  }),

  // Getters: funciones para obtener datos del estado de forma calculada
  getters: {
    // Es una forma de obtener el estado de isAuthenticated
    // Es más limpio que acceder a state.isAuthenticated directamente
    isLoggedIn: (state) => state.isAuthenticated,
  },

  // Acciones: funciones para cambiar el estado
  actions: {
    // Acción para iniciar sesión
    login(userData, token) {
      this.user = userData;
      this.token = token;
      this.isAuthenticated = true;

      // Opcional: guardar el token en el almacenamiento local para persistencia
      localStorage.setItem('authToken', token);
    },

    // Acción para cerrar sesión
    logout() {
      this.user = null;
      this.token = null;
      this.isAuthenticated = false;

      // Opcional: limpiar el almacenamiento local
      localStorage.removeItem('authToken');
    },

    // Acción para cargar el estado desde el almacenamiento local al iniciar la app
    checkAuthStatus() {
      const storedToken = localStorage.getItem('authToken');
      if (storedToken) {
        this.token = storedToken;
        this.isAuthenticated = true;
        // Aquí podrías hacer una petición a la API para obtener los datos del usuario
        // basándote en el token
      }
    }
  },
})
